create extension if not exists pgcrypto;
create or replace function public.set_updated_at() returns trigger as $$ begin new.updated_at = now(); return new; end; $$ language plpgsql;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, full_name text, phone text, organization text, role text not null default 'student', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint profiles_role_check check (role in ('student','admin')));
create table if not exists public.academy_courses (id uuid primary key default gen_random_uuid(), title text not null, slug text not null unique, category text not null, short_description text, description text, cover_image_url text, level text, duration text, language text default 'fr', status text not null default 'draft', price_amount numeric(10,2), price_currency text default 'HTG', is_free boolean not null default false, published_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint academy_courses_status_check check (status in ('draft','published','archived')), constraint academy_courses_level_check check (level in ('beginner','intermediate','advanced') or level is null));
create table if not exists public.academy_modules (id uuid primary key default gen_random_uuid(), course_id uuid not null references public.academy_courses(id) on delete cascade, title text not null, description text, position integer not null default 0, status text not null default 'published', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint academy_modules_status_check check (status in ('draft','published','archived')));
create table if not exists public.academy_lessons (id uuid primary key default gen_random_uuid(), course_id uuid not null references public.academy_courses(id) on delete cascade, module_id uuid references public.academy_modules(id) on delete set null, title text not null, content text, video_url text, position integer not null default 0, is_preview boolean not null default false, duration text, status text not null default 'published', created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint academy_lessons_status_check check (status in ('draft','published','archived')));
create table if not exists public.academy_resources (id uuid primary key default gen_random_uuid(), course_id uuid not null references public.academy_courses(id) on delete cascade, lesson_id uuid references public.academy_lessons(id) on delete set null, title text not null, description text, file_url text, external_url text, resource_type text not null default 'document', is_downloadable boolean not null default true, position integer not null default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint academy_resources_type_check check (resource_type in ('document','pdf','video','link','image','other')));
create table if not exists public.academy_enrollments (id uuid primary key default gen_random_uuid(), student_id uuid not null references auth.users(id) on delete cascade, course_id uuid not null references public.academy_courses(id) on delete cascade, status text not null default 'pending', access_source text not null default 'manual', payment_reference text, amount_paid numeric(10,2), currency text default 'HTG', validated_by uuid references auth.users(id), validated_at timestamptz, expires_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(student_id, course_id), constraint academy_enrollments_status_check check (status in ('pending','active','rejected','expired','completed')), constraint academy_enrollments_access_source_check check (access_source in ('manual','payment','free','admin_grant')));
create table if not exists public.academy_lesson_progress (id uuid primary key default gen_random_uuid(), student_id uuid not null references auth.users(id) on delete cascade, course_id uuid not null references public.academy_courses(id) on delete cascade, lesson_id uuid not null references public.academy_lessons(id) on delete cascade, is_completed boolean not null default false, completed_at timestamptz, last_position_seconds integer default 0, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(student_id, lesson_id));
create table if not exists public.academy_certificates (id uuid primary key default gen_random_uuid(), certificate_id text not null unique, student_id uuid not null references auth.users(id) on delete cascade, course_id uuid not null references public.academy_courses(id) on delete cascade, student_full_name text not null, course_title text not null, issued_at timestamptz not null default now(), status text not null default 'issued', verification_url text, pdf_url text, qr_code_url text, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), constraint academy_certificates_status_check check (status in ('issued','revoked','expired')));
do $$ declare t text; begin foreach t in array array['profiles','academy_courses','academy_modules','academy_lessons','academy_resources','academy_enrollments','academy_lesson_progress','academy_certificates'] loop execute format('drop trigger if exists set_%s_updated_at on public.%I', t, t); execute format('create trigger set_%s_updated_at before update on public.%I for each row execute function public.set_updated_at()', t, t); end loop; end $$;
alter table public.profiles enable row level security; alter table public.academy_courses enable row level security; alter table public.academy_modules enable row level security; alter table public.academy_lessons enable row level security; alter table public.academy_resources enable row level security; alter table public.academy_enrollments enable row level security; alter table public.academy_lesson_progress enable row level security; alter table public.academy_certificates enable row level security;
drop policy if exists "Public can read published academy courses" on public.academy_courses; create policy "Public can read published academy courses" on public.academy_courses for select to anon, authenticated using (status='published');
drop policy if exists "Public can read published academy modules" on public.academy_modules; create policy "Public can read published academy modules" on public.academy_modules for select to anon, authenticated using (status='published' and exists(select 1 from public.academy_courses c where c.id=course_id and c.status='published'));
drop policy if exists "Public can read preview academy lessons" on public.academy_lessons; create policy "Public can read preview academy lessons" on public.academy_lessons for select to anon, authenticated using (status='published' and is_preview=true and exists(select 1 from public.academy_courses c where c.id=course_id and c.status='published'));
drop policy if exists "Students can read own profile" on public.profiles; create policy "Students can read own profile" on public.profiles for select to authenticated using (id=auth.uid());
drop policy if exists "Students can update own profile" on public.profiles; create policy "Students can update own profile" on public.profiles for update to authenticated using (id=auth.uid()) with check (id=auth.uid());
drop policy if exists "Students can read own enrollments" on public.academy_enrollments; create policy "Students can read own enrollments" on public.academy_enrollments for select to authenticated using (student_id=auth.uid());
drop policy if exists "Students can read own lesson progress" on public.academy_lesson_progress; create policy "Students can read own lesson progress" on public.academy_lesson_progress for select to authenticated using (student_id=auth.uid());
drop policy if exists "Students can upsert own lesson progress" on public.academy_lesson_progress; create policy "Students can upsert own lesson progress" on public.academy_lesson_progress for insert to authenticated with check (student_id=auth.uid());
drop policy if exists "Students can update own lesson progress" on public.academy_lesson_progress; create policy "Students can update own lesson progress" on public.academy_lesson_progress for update to authenticated using (student_id=auth.uid()) with check (student_id=auth.uid());
drop policy if exists "Students can read own certificates" on public.academy_certificates; create policy "Students can read own certificates" on public.academy_certificates for select to authenticated using (student_id=auth.uid());
drop policy if exists "Public can verify issued certificates" on public.academy_certificates; create policy "Public can verify issued certificates" on public.academy_certificates for select to anon, authenticated using (status='issued');
